    def findSubstring(self, s: str, words: List[str]) -> List[int]:
        word_set = Counter(words)
        w_length = len(words[0])

        result = []

        for index in range(len(s) - w_length + 1):
            slice = s[index:index + w_length]

            if slice in word_set:
                temp_set = word_set.copy()
                temp_set[slice] -= 1
                if temp_set[slice] == 0:
                    temp_set.pop(slice)

